1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge case: empty items ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // --- Base premiums for main items (with first insurance applied per item; assume newcomer 0 yrs) ---
15	  it("single sword (plain, newcomer) → 100 base + 10 first insurance + 5 fee = 115 G", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result.results[0]).toEqual({ premium: 115 });
21	  });
22	  it("single amulet (plain, newcomer) → 60 + 6 + 5 = 71 G", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result.results[0]).toEqual({ premium: 71 });
28	  });
29	  it.todo("single staff (plain, newcomer) → 80 + 8 + 5 = 93 G");
30	  it.todo("single potion (plain, newcomer) → 40 + 4 + 5 = 49 G");
31	
32	  // --- Components: runes and moonstones ---
33	  it.todo("2 runes → 50 G base premium (+ first insurance + fee)");
34	  it.todo("3 runes → 60 G base premium (block applies)");
35	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
36	  it.todo("7 runes → 175 G base premium (no block — 7 is not exactly 3)");
37	
38	  // --- 'Alike' components clarification ---
39	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
40	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
41	
42	  // --- Item-specific modifiers (no policy-wide modifiers besides first insurance) ---
43	  it.todo("cursed sword (newcomer) → 100 + 50 curse + 10 first insurance + 5 fee = 165 G");
44	  it.todo("sword with enchantment 5 → high-enchantment surcharge applies (100 + 30 + 10 + 5 = 145)");
45	  it.todo("sword with enchantment 4 → no high-enchantment surcharge (100 + 10 + 5 = 115)");
46	  it.todo("cursed sword with enchantment 5 → both surcharges apply (100 + 50 + 30 + 10 + 5 = 195)");
47	
48	  // --- Modifier scope: cursed applies only to the cursed item in a multi-item policy ---
49	  it.todo("cursed sword + plain amulet (newcomer): item bases 100+60=160; curse 50 (on sword only); first ins 21 (10% of 210); +5 fee = 236 G");
50	
51	  // --- Policy-wide modifiers ---
52	  it.todo("long-standing customer (exactly 2 years) with plain sword: 100 base - 20 loyalty + 10 first insurance + 5 fee = 95 G");
53	  it.todo("customer's second quote (plain sword): 100 + 10 first insurance - 15 follow-up + 5 fee = 100 G");
54	
55	  // --- Integration examples ---
56	  it.todo("Newcomer with cursed sword (steel, ench 3): premium 165 G");
57	  it.todo("Long-standing customer (3 yrs) second contract, cursed sword (steel, ench 7): premium 160 G");
58	  it.todo("first insurance surcharge applies to each item even for follow-up contract");
59	
60	  // --- Rounding in MHPCO favor ---
61	  it.todo("premium yielding 197.5 G → 198 G (rounded up)");
62	
63	  // --- Claim: standard reimbursement ---
64	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
65	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G");
66	
67	  // --- Claim: high enchantment clause ---
68	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
69	
70	  // --- Claim: dragon material clause ---
71	  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
72	
73	  // --- Claim: dragon precedence over high enchantment ---
74	  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins per spec interpretation: 500-100)");
75	  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G");
76	
77	  // --- Claim: rounding payout down ---
78	  it.todo("payout yielding 350.5 G → 350 G (rounded down)");
79	
80	  // --- Claim: deductible per damage event (per damaged item) ---
81	  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout = 600 G (100 deductible per item)");
82	
83	  // --- Claim: multiple items of same type ---
84	  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G");
85	  it.todo("policy with two swords; damages array with two sword entries → each gets own deductible");
86	  it.todo("damages array contains more entries of a type than policy covers → CLI exits non-zero, claim rejected");
87	
88	  // --- Claim: cap ---
89	  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
90	  it.todo("cursed sword (premium with mods 165) → cap 2000 G (based on unmodified insurance value)");
91	  it.todo("policy covers sword + 3 runes → insurance sum 1750 G (block doesn't affect insurance sum)");
92	  it.todo("sword cap 2000: first claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");
93	
94	  // --- Error cases ---
95	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero, error to stderr, no results");
96	  it.todo("claim references item not in policy → CLI exits non-zero, error to stderr");
97	  it.todo("claim with negative damage amount (-200) → CLI exits non-zero, error to stderr");
98	
99	  // --- CLI integration ---
100	  it.todo("CLI: end-to-end scenario with quote + claim produces results array of correct length and shape");
101	});
